                                            return;
                                        } else {
                                            ds_tariff_upload.setCellData(i, "dptDistrictCd", rtnList[0]);
                                            ds_tariff_upload.setCellData(i, "dptDistrictNm", rtnList[1]);
                                        }
                                    }, 
                                    ds_TmptranstrfList.getCellData(i, colid),    
                                    ds_TmptranstrfList.getCellData(i, colid),    
                                    "T",        
                                    null,       
                                    null,   
                                    null,   
                                    null,       
                                    ',,'+ ds_ctrtBase.getCellData(0, "ctrtDistrictCd") + ',,,,' + ds_tariff.getCellData(i, "commCd"),
